def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        series_sum = 0.0
        for n in range(1, 20):
            base_factor = (np.sin(n) + 1.5) / 3
            decay = np.exp(-n/10)
            power_component = ratio ** n if ratio < 1 else 1
            series_sum += base_factor * decay * power_component
            if n % 4 == 0:
                score += np.log1p(n * ratio) * base_factor
            else:
                score += np.sqrt(n) * power_component * base_factor
        leftover_ratio = (capacity - item) / capacity
        if leftover_ratio < 0.05:
            score *= 2.8
        elif leftover_ratio < 0.15:
            score *= 1.7
        elif leftover_ratio < 0.25:
            score *= 1.2
        else:
            score *= 0.85
        mod_values = [int(capacity) % p == 0 for p in [2,3,5,11]]
        if all(mod_values):
            score -= 0.22 * (capacity / 20)
        elif mod_values[0] and mod_values[2]:
            score -= 0.15 * (capacity / 18)
        elif mod_values[1] and mod_values[3]:
            score -= 0.18 * (capacity / 22)
        elif mod_values[0]:
            score -= 0.06 * (capacity / 14)
        elif mod_values[1]:
            score -= 0.08 * (capacity / 16)
        elif mod_values[2]:
            score -= 0.11 * (capacity / 12)
        elif mod_values[3]:
            score -= 0.09 * (capacity / 25)
        else:
            score -= 0.04 * (capacity / 30)
        penalty = 0
        for k in range(1,8):
            val = capacity - item * k
            abs_diff = abs(val)
            threshold = 0.01 * capacity * k
            if abs_diff < threshold:
                penalty += 0.3 * k
            elif abs_diff < 3 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.07 * k
            if val > 0 and val % 2 == 0:
                penalty += 0.05 * (k % 3)
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1,5):
                cmp_val = capacity / m
                if abs(cmp_val - item) < 0.015 * cmp_val:
                    score *= (1 + 0.07 * m)
                if m % 2 == 0 and item % 1 < 0.001 * m:
                    score += 0.05 * m
        noise_factor = np.cos(capacity) * 0.03
        score = max(0, score + noise_factor)
        priorities[i] = score
    return priorities
